script:
frappe.ui.form.on('Production Plan', {
	refresh(frm) {
        // Add a custom button to the form under the "View" group
        frm.add_custom_button(__('Production Cost Summary'), function() {
            // Get the current Production Plan Id
            var production_plan_id = frm.doc.name;

            // Open the report with the filter applied
            frappe.set_route('query-report', 'Production Cost Summary', {
                'production_plan_id': production_plan_id
            });
        }, 'View'); // Changed 'Reports' to 'View'

        // Add a custom button to the form under the "View" group
        frm.add_custom_button(__('Picking List'), function() {
            // Get the current Production Plan Id
            var production_plan_id = frm.doc.name;

            // Open the report with the filter applied
            frappe.set_route('query-report', 'Production Picking List', {
                'production_plan_id': production_plan_id
            });
        }, 'View'); // Changed 'Reports' to 'View'
    }
})

frappe.ui.form.on("Production Plan", {
    refresh(frm) {
        console.log("PRODUCTION PLAN CLIENT SCRIPT");
        // Override the item_code query for po_items with additional filter
        frm.set_query("item_code", "po_items", (doc, cdt, cdn) => {
            return {
                query: "erpnext.controllers.queries.item_query",
                filters: {
                    is_stock_item: 1,
                    include_item_in_manufacturing: 1
                }
            };
        });
    }
});

frappe.ui.form.on('Purchase Order', {
  supplier(frm) {
    if (!frm.doc.supplier) return;
    frappe.db.get_value('Supplier',
      frm.doc.supplier,
      'custom_default_incoterm',
      (r) => {
        if (r.custom_default_incoterm) {
          frm.set_value('incoterm', r.custom_default_incoterm);
        }
        else {
          frm.set_value('incoterm', '');
        }

      }
    );
  }
});

frappe.ui.form.on("Item", {
	custom_net_weight_per_unit: update_weight_per_unit,
	custom_tare_weight_per_unit: update_weight_per_unit,
	validate: update_weight_per_unit
});

function update_weight_per_unit(frm) {
	const net_weight = flt(frm.doc.custom_net_weight_per_unit);
	const tare_weight = flt(frm.doc.custom_tare_weight_per_unit);
	const total_weight = net_weight + tare_weight;

	if (flt(frm.doc.weight_per_unit) !== total_weight) {
		frm.set_value("weight_per_unit", total_weight);
	}
}
